//! Read the Async Data Output Frequency (register 7) from a VectorNav VN-100.
//!
//! The VN-100 speaks an ASCII protocol over a serial port. To read a register
//! you send a "Read Register" (RRG) command:
//!
//!     $VNRRG,07*XX\r\n
//!
//! where `XX` is the 8-bit XOR checksum of every character between `$` and `*`.
//! The device replies with:
//!
//!     $VNRRG,07,<freq>*YY\r\n
//!
//! where `<freq>` is the async output rate in Hz.
//!
//! Usage: rdwr_vn100 [port] [baud]
//!   port  serial device      (default: /dev/ttyUSB0)
//!   baud  baud rate          (default: 115200, the VN-100 factory default)

use std::io::{BufRead, BufReader, Write};
use std::time::Duration;

/// Compute the VN-100 checksum: XOR of all bytes in `payload`.
fn checksum(payload: &str) -> u8 {
    payload.bytes().fold(0u8, |acc, b| acc ^ b)
}

/// Build a full command line (including `$`, `*`, checksum and CRLF) from the
/// payload that sits between `$` and `*`, e.g. `"VNRRG,07"`.
fn build_command(payload: &str) -> String {
    format!("${}*{:02X}\r\n", payload, checksum(payload))
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut args = std::env::args().skip(1);
    let port_name = args.next().unwrap_or_else(|| "/dev/ttyUSB0".to_string());
    let baud: u32 = args
        .next()
        .map(|s| s.parse())
        .transpose()?
        .unwrap_or(115_200);

    println!("Opening {port_name} at {baud} baud...");
    let mut port = serialport::new(&port_name, baud)
        .timeout(Duration::from_millis(1000))
        .open()?;

    // Send the read-register-7 command.
    let cmd = build_command("VNRRG,07");
    print!("TX: {cmd}");
    port.write_all(cmd.as_bytes())?;
    port.flush()?;

    // The VN-100 may be streaming async data, so read lines until we see the
    // reply to our request (or run out of patience).
    let mut reader = BufReader::new(port);
    for _ in 0..50 {
        let mut line = String::new();
        if reader.read_line(&mut line)? == 0 {
            break; // timeout / EOF
        }
        let line = line.trim();
        if let Some(rate) = parse_rrg07(line) {
            println!("RX: {line}");
            println!("Async output rate: {rate} Hz");
            return Ok(());
        }
    }

    Err("no $VNRRG,07 response received from device".into())
}

/// Parse the rate out of a `$VNRRG,07,<freq>*XX` response line.
/// Returns `None` for any other (e.g. async) line.
fn parse_rrg07(line: &str) -> Option<u32> {
    let body = line.strip_prefix("$VNRRG,07,")?;
    let freq = body.split('*').next()?;
    freq.trim().parse().ok()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn checksum_matches_known_value() {
        // Documented VN-100 example: $VNRRG,07*<checksum>
        assert_eq!(format!("{:02X}", checksum("VNRRG,07")), "6E");
    }

    #[test]
    fn builds_full_command() {
        assert_eq!(build_command("VNRRG,07"), "$VNRRG,07*6E\r\n");
    }

    #[test]
    fn parses_response() {
        assert_eq!(parse_rrg07("$VNRRG,07,40*4C"), Some(40));
        assert_eq!(parse_rrg07("$VNYMR,+010.0*7F"), None);
    }
}

