    if persist {
        let wnv = build_command("VNWNV");
        print!("TX: {wnv}");
        reader.get_mut().write_all(wnv.as_bytes())?;
        reader.get_mut().flush()?;
        let confirm = read_reply(&mut reader, |l| l.starts_with("$VNWNV"))?
            .ok_or("no $VNWNV confirmation received from device")?;
        println!("RX: {confirm}");
        println!("Settings written to non-volatile memory.");
    }

    Ok(())
}

