        |l| l.starts_with("$VNWRG,75"),
        "device did not accept the binary output config (a $VNERR here would mean it won't fit)",
    )?;
    println!(
        "Configured binary output: Common[TimeStartup, Accel] @ {} Hz (divisor {divisor}, {} bytes/frame).",
        800 / divisor,
