1	//! Read or set the Async Data Output Frequency (register 7) on a VectorNav VN-100,
2	//! and change the device's serial baud rate (register 5).
3	//!
4	//! The VN-100 speaks an ASCII protocol over a serial port. Each command is
5	//!
6	//!     $<payload>*XX\r\n
7	//!
8	//! where `XX` is the 8-bit XOR checksum of every character of `<payload>`
9	//! (i.e. everything between `$` and `*`).
10	//!
11	//! Read Register 7:   $VNRRG,07*XX        -> reply $VNRRG,07,<freq>*YY
12	//! Write Register 7:  $VNWRG,07,<freq>*XX -> reply $VNWRG,07,<freq>*YY
13	//! Write Register 5:  $VNWRG,05,<baud>*XX -> reply $VNWRG,05,<baud>*YY  (serial baud)
14	//! Write Settings:    $VNWNV*XX           -> reply $VNWNV*YY            (save to flash)
15	//! Error response:    $VNERR,<code>*XX
16	//!
17	//! `<freq>` is the async output rate in Hz. The VN-100 has no command to query
18	//! the allowable rates: the set is fixed in firmware (see `VALID_RATES`), and
19	//! writing an out-of-range value returns a `$VNERR` response.
20	
21	use std::io::{Read, Write};
22	use std::time::{Duration, Instant};
23	
24	/// Frequencies (Hz) the VN-100 accepts for the async data output rate.
25	const VALID_RATES: &[u32] = &[1, 2, 4, 5, 10, 20, 25, 40, 50, 100, 200];
26	
27	/// Serial baud rates the VN-100 supports (register 5).
28	const VALID_BAUDS: &[u32] = &[
29	    9600, 19200, 38400, 57600, 115200, 128000, 230400, 460800, 921600,
30	];
31	
32	/// A selectable binary-output field (all from the "Common" group, group 1):
33	/// CLI name, the group-1 bit it occupies, and its on-wire byte size.
34	struct Field {
35	    name: &'static str,
36	    bit: u8,
37	    size: usize,
38	}
39	
40	/// The `--fields` vocabulary (Common group only — keeps the frame to one group).
41	const FIELDS: &[Field] = &[
42	    Field {
43	        name: "time",
44	        bit: 0,
45	        size: 8,
46	    }, // TimeStartup, u64 ns
47	    Field {
48	        name: "ypr",
49	        bit: 3,
50	        size: 12,
51	    }, // YawPitchRoll, 3×f32 deg
52	    Field {
53	        name: "quat",
54	        bit: 4,
55	        size: 16,
56	    }, // Quaternion, 4×f32
57	    Field {
58	        name: "gyro",
59	        bit: 5,
60	        size: 12,
61	    }, // AngularRate, 3×f32 rad/s
62	    Field {
63	        name: "accel",
64	        bit: 8,
65	        size: 12,
66	    }, // Accel, 3×f32 m/s^2
67	    Field {
68	        name: "imu",
69	        bit: 9,
70	        size: 24,
71	    }, // uncomp Accel+Gyro, 6×f32
72	    Field {
73	        name: "magpres",
74	        bit: 10,
75	        size: 20,
76	    }, // Mag(3×f32)+Temp+Pres
77	];
78	
79	fn lookup_field(name: &str) -> Option<&'static Field> {
80	    FIELDS.iter().find(|f| f.name == name)
81	}
82	
83	fn field_names() -> String {
84	    FIELDS.iter().map(|f| f.name).collect::<Vec<_>>().join(", ")
85	}
86	
87	/// Parse a comma-separated `--fields` list into Common-group fields, ordered by
88	/// bit (the order the device emits them), de-duplicated.
89	fn parse_fields(list: &str) -> Result<Vec<&'static Field>, String> {
90	    let mut out: Vec<&'static Field> = Vec::new();
91	    for name in list.split(',').map(str::trim).filter(|s| !s.is_empty()) {
92	        let f = lookup_field(name)
93	            .ok_or_else(|| format!("unknown field `{name}`; choose from {}", field_names()))?;
94	        if !out.iter().any(|g| g.name == f.name) {
95	            out.push(f);
96	        }
97	    }
98	    if out.is_empty() {
99	        return Err("--fields needs at least one field".into());
100	    }
101	    out.sort_by_key(|f| f.bit);
102	    Ok(out)
103	}
104	
105	/// Default binary field set: timestamp + acceleration.
106	fn default_fields() -> Vec<&'static Field> {
107	    vec![
108	        lookup_field("time").unwrap(),
109	        lookup_field("accel").unwrap(),
110	    ]
111	}
112	
113	/// Compute the VN-100 checksum: XOR of all bytes in `payload`.
114	fn checksum(payload: &str) -> u8 {
115	    payload.bytes().fold(0u8, |acc, b| acc ^ b)
116	}
117	
118	/// Build a full command line (including `$`, `*`, checksum and CRLF) from the
119	/// payload that sits between `$` and `*`, e.g. `"VNRRG,07"`.
120	fn build_command(payload: &str) -> String {
121	    format!("${}*{:02X}\r\n", payload, checksum(payload))
122	}
123	
124	/// Verify the trailing `*XX` checksum of a received `$...*XX` line.
125	fn verify_checksum(line: &str) -> Result<(), String> {
126	    let payload = line.strip_prefix('$').ok_or("reply missing leading '$'")?;
127	    let (payload, sum) = payload
128	        .rsplit_once('*')
129	        .ok_or("reply missing '*' checksum delimiter")?;
130	    let given = u8::from_str_radix(sum.trim(), 16)
131	        .map_err(|_| format!("malformed checksum field {sum:?}"))?;
132	    let actual = checksum(payload);
133	    if given == actual {
134	        Ok(())
135	    } else {
136	        Err(format!(
137	            "checksum mismatch: reply says {given:02X}, computed {actual:02X}"
138	        ))
139	    }
140	}
141	
142	/// Human-readable description of a VN-100 system error code.
143	fn error_description(code: u8) -> &'static str {
144	    match code {
145	        1 => "hard fault",
146	        2 => "serial buffer overflow",
147	        3 => "invalid checksum",
148	        4 => "invalid command",
149	        5 => "not enough parameters",
150	        6 => "too many parameters",
151	        7 => "invalid parameter",
152	        8 => "invalid register",
153	        9 => "unauthorized access",
154	        10 => "watchdog reset",
155	        11 => "output buffer overflow",
156	        12 => "insufficient baud rate",
157	        255 => "error buffer overflow",
158	        _ => "unknown error",
159	    }
160	}
161	
162	/// Turn a `$VNERR,<code>*XX` line into a readable message. The code is hex.
163	fn vnerr_message(line: &str) -> String {
164	    let code = line
165	        .strip_prefix("$VNERR,")
166	        .and_then(|b| b.split('*').next())
167	        .map(str::trim)
168	        .and_then(|c| u8::from_str_radix(c, 16).ok());
169	    match code {
170	        Some(n) => {
171	            let mut msg = format!("device error 0x{n:02X} ({n}): {}", error_description(n));
172	            if n == 12 {
173	                // By far the most likely error when setting a high output rate.
174	                msg.push_str(
175	                    " — the configured async message won't fit at this output rate over the \
176	                     current serial baud; raise the baud (e.g. `baud 921600`) or shorten the \
177	                     async message (register 6)",
178	                );
179	            }
180	            msg
181	        }
182	        None => format!("device error: {line}"),
183	    }
184	}
185	
186	/// Parse the rate out of a `$VN(R|W)RG,07,<freq>*XX` response line.
187	/// Returns `None` for any other (e.g. async) line.
188	fn parse_reg07(line: &str) -> Option<u32> {
189	    let body = line
190	        .strip_prefix("$VNRRG,07,")
191	        .or_else(|| line.strip_prefix("$VNWRG,07,"))?;
192	    let freq = body.split('*').next()?;
193	    freq.trim().parse().ok()
194	}
195	
196	struct Config {
197	    port: String,
198	    baud: u32,
199	}
200	
201	enum Command {
202	    Help,
203	    GetHz,
204	    SetHz {
205	        hz: u32,
206	        persist: bool,
207	    },
208	    SetBaud {
209	        baud: u32,
210	        persist: bool,
211	    },
212	    Reset,
213	    FactoryReset,
214	    /// Read any register (generic ASCII Read Register).
215	    Rrg {
216	        id: u8,
217	    },
218	    /// Write any register (generic ASCII Write Register).
219	    Wrg {
220	        id: u8,
221	        params: Vec<String>,
222	    },
223	    /// Configure an output (ASCII async by default, or binary with `--bin`) and
224	    /// measure the achieved rate, then restore prior state.
225	    Bench {
226	        binary: bool,
227	        hz: u32,
228	        secs: u64,
229	        fields: Vec<&'static Field>,
230	    },
231	}
232	
