1	//! `rdwr_vn100` — read and configure a VectorNav VN-100 IMU over serial.
2	//!
3	//! The VN-100 speaks an ASCII protocol over a serial port. Each command is
4	//!
5	//!     $<payload>*XX\r\n
6	//!
7	//! where `XX` is the 8-bit XOR checksum of every character of `<payload>`
8	//! (i.e. everything between `$` and `*`). Replies echo the same form; binary
9	//! outputs (register 75) use a packed frame ending in a 16-bit CRC instead.
10	//!
11	//! Commands implemented here:
12	//!   get-hz / set-hz       read/write the async output rate    (register 7)
13	//!   baud                  change the serial baud rate          (register 5)
14	//!   rrg / wrg             generic read/write of any register   ($VNRRG / $VNWRG)
15	//!   bench                 configure an output (ASCII async by default, or a
16	//!                         binary output with --bin) and measure the achieved
17	//!                         rate, to see what fits a given baud
18	//!   reset / factory-reset reboot / restore defaults            ($VNRST / $VNRFS)
19	//!
20	//! Key VN messages:
21	//!   $VNRRG,<id>*XX          -> $VNRRG,<id>,<f1>,...*YY   (read register)
22	//!   $VNWRG,<id>,<f1>,...*XX  -> echo                     (write register)
23	//!   $VNWNV*XX               -> $VNWNV*YY                 (save all to flash)
24	//!   $VNERR,<code>*XX                                     (error; see error_description)
25	//!
26	//! The async output rate (register 7) is one of a fixed firmware set
27	//! (`VALID_RATES`); a value that's out of range — or too much data for the
28	//! current baud — returns a `$VNERR` (0x0C = insufficient baud rate).
29	
30	use std::io::{Read, Write};
31	use std::time::{Duration, Instant};
32	
33	/// Frequencies (Hz) the VN-100 accepts for the async data output rate.
34	const VALID_RATES: &[u32] = &[1, 2, 4, 5, 10, 20, 25, 40, 50, 100, 200];
35	
36	/// Serial baud rates the VN-100 supports (register 5).
37	const VALID_BAUDS: &[u32] = &[
38	    9600, 19200, 38400, 57600, 115200, 128000, 230400, 460800, 921600,
39	];
40	
41	/// A selectable binary-output field (all from the "Common" group, group 1):
42	/// CLI name, the group-1 bit it occupies, and its on-wire byte size.
43	struct Field {
44	    name: &'static str,
45	    bit: u8,
46	    size: usize,
47	}
48	
49	/// The `--fields` vocabulary (Common group only — keeps the frame to one group).
50	const FIELDS: &[Field] = &[
51	    Field {
52	        name: "time",
53	        bit: 0,
54	        size: 8,
55	    }, // TimeStartup, u64 ns
56	    Field {
57	        name: "ypr",
58	        bit: 3,
59	        size: 12,
60	    }, // YawPitchRoll, 3×f32 deg
61	    Field {
62	        name: "quat",
63	        bit: 4,
64	        size: 16,
65	    }, // Quaternion, 4×f32
66	    Field {
67	        name: "gyro",
68	        bit: 5,
69	        size: 12,
70	    }, // AngularRate, 3×f32 rad/s
71	    Field {
72	        name: "accel",
73	        bit: 8,
74	        size: 12,
75	    }, // Accel, 3×f32 m/s^2
76	    Field {
77	        name: "imu",
78	        bit: 9,
79	        size: 24,
80	    }, // uncomp Accel+Gyro, 6×f32
81	    Field {
82	        name: "magpres",
83	        bit: 10,
84	        size: 20,
85	    }, // Mag(3×f32)+Temp+Pres
86	];
87	
88	fn lookup_field(name: &str) -> Option<&'static Field> {
89	    FIELDS.iter().find(|f| f.name == name)
90	}
91	
92	fn field_names() -> String {
93	    FIELDS.iter().map(|f| f.name).collect::<Vec<_>>().join(", ")
94	}
95	
96	/// Parse a comma-separated `--fields` list into Common-group fields, ordered by
97	/// bit (the order the device emits them), de-duplicated.
98	fn parse_fields(list: &str) -> Result<Vec<&'static Field>, String> {
99	    let mut out: Vec<&'static Field> = Vec::new();
100	    for name in list.split(',').map(str::trim).filter(|s| !s.is_empty()) {
101	        let f = lookup_field(name)
102	            .ok_or_else(|| format!("unknown field `{name}`; choose from {}", field_names()))?;
103	        if !out.iter().any(|g| g.name == f.name) {
104	            out.push(f);
105	        }
106	    }
107	    if out.is_empty() {
108	        return Err("--fields needs at least one field".into());
109	    }
110	    out.sort_by_key(|f| f.bit);
111	    Ok(out)
112	}
113	
114	/// Default binary field set: timestamp + acceleration.
115	fn default_fields() -> Vec<&'static Field> {
116	    vec![
117	        lookup_field("time").unwrap(),
118	        lookup_field("accel").unwrap(),
119	    ]
120	}
121	
122	/// Compute the VN-100 checksum: XOR of all bytes in `payload`.
123	fn checksum(payload: &str) -> u8 {
124	    payload.bytes().fold(0u8, |acc, b| acc ^ b)
125	}
126	
127	/// Build a full command line (including `$`, `*`, checksum and CRLF) from the
128	/// payload that sits between `$` and `*`, e.g. `"VNRRG,07"`.
129	fn build_command(payload: &str) -> String {
130	    format!("${}*{:02X}\r\n", payload, checksum(payload))
131	}
132	
133	/// Verify the trailing `*XX` checksum of a received `$...*XX` line.
134	fn verify_checksum(line: &str) -> Result<(), String> {
135	    let payload = line.strip_prefix('$').ok_or("reply missing leading '$'")?;
136	    let (payload, sum) = payload
137	        .rsplit_once('*')
138	        .ok_or("reply missing '*' checksum delimiter")?;
139	    let given = u8::from_str_radix(sum.trim(), 16)
140	        .map_err(|_| format!("malformed checksum field {sum:?}"))?;
141	    let actual = checksum(payload);
142	    if given == actual {
143	        Ok(())
144	    } else {
145	        Err(format!(
146	            "checksum mismatch: reply says {given:02X}, computed {actual:02X}"
147	        ))
148	    }
149	}
150	
151	/// Human-readable description of a VN-100 system error code.
152	fn error_description(code: u8) -> &'static str {
153	    match code {
154	        1 => "hard fault",
155	        2 => "serial buffer overflow",
156	        3 => "invalid checksum",
157	        4 => "invalid command",
158	        5 => "not enough parameters",
159	        6 => "too many parameters",
160	        7 => "invalid parameter",
161	        8 => "invalid register",
162	        9 => "unauthorized access",
163	        10 => "watchdog reset",
164	        11 => "output buffer overflow",
165	        12 => "insufficient baud rate",
166	        255 => "error buffer overflow",
167	        _ => "unknown error",
168	    }
169	}
170	
171	/// Turn a `$VNERR,<code>*XX` line into a readable message. The code is hex.
172	fn vnerr_message(line: &str) -> String {
173	    let code = line
174	        .strip_prefix("$VNERR,")
175	        .and_then(|b| b.split('*').next())
176	        .map(str::trim)
177	        .and_then(|c| u8::from_str_radix(c, 16).ok());
178	    match code {
179	        Some(n) => {
180	            let mut msg = format!("device error 0x{n:02X} ({n}): {}", error_description(n));
181	            if n == 12 {
182	                // By far the most likely error when setting a high output rate.
183	                msg.push_str(
184	                    " — the configured async message won't fit at this output rate over the \
185	                     current serial baud; raise the baud (e.g. `baud 921600`) or shorten the \
186	                     async message (register 6)",
187	                );
188	            }
189	            msg
190	        }
191	        None => format!("device error: {line}"),
192	    }
193	}
194	
195	/// Parse the rate out of a `$VN(R|W)RG,07,<freq>*XX` response line.
196	/// Returns `None` for any other (e.g. async) line.
197	fn parse_reg07(line: &str) -> Option<u32> {
198	    let body = line
199	        .strip_prefix("$VNRRG,07,")
200	        .or_else(|| line.strip_prefix("$VNWRG,07,"))?;
201	    let freq = body.split('*').next()?;
202	    freq.trim().parse().ok()
203	}
204	
205	/// Parse register 6 (Async Data Output Type / ADOR) value from a reply.
206	fn parse_reg06(line: &str) -> Option<u8> {
207	    let body = line
208	        .strip_prefix("$VNRRG,06,")
209	        .or_else(|| line.strip_prefix("$VNWRG,06,"))?;
210	    body.split('*').next()?.trim().parse().ok()
211	}
